Thread 1: if (flag == 0) { flag = 1; doA(); }
Thread 2: if (flag == 0) { flag = 1; doA(); }  // Both might execute doA()

// ❌ ABBA Deadlock
Thread 1: lock(A); lock(B);
Thread 2: lock(B); lock(A);  // Deadlock

// ✅ Prevention: Same order
Thread 1: lock(A); lock(B);
Thread 2: lock(A); lock(B);  // No deadlock

